from django.shortcuts import render, get_object_or_404
from django.views import View
from django.views.generic import ListView, DetailView
from django.db.models import Q
from datetime import datetime, timedelta
from .models import Barco, Categoria, Puerto, Fabricante


class HomeView(View):
    def get(self, request):
        barcos = Barco.objects.all()
        categorias = Categoria.objects.all()
        puertos = Puerto.objects.all()
        fabricantes = Fabricante.objects.all()

        context = {
            'barcos': barcos,
            'categorias': categorias,
            'puertos': puertos,
            'fabricantes': fabricantes,
        }
        return render(request, 'catalog/home.html', context)


class BarcoListView(View):
    def get(self, request):
        barcos = Barco.objects.all()
        categorias = Categoria.objects.all()
        puertos = Puerto.objects.all()
        fabricantes = Fabricante.objects.all()

        # Filtros
        categoria_id = request.GET.get('categoria')
        puerto_id = request.GET.get('puerto')
        fabricante_id = request.GET.get('fabricante')
        precio_min = request.GET.get('precio_min')
        precio_max = request.GET.get('precio_max')
        capacidad_min = request.GET.get('capacidad_min')
        fecha_inicio = request.GET.get('fecha_inicio')
        fecha_fin = request.GET.get('fecha_fin')

        if categoria_id:
            barcos = barcos.filter(categoria_id=categoria_id)
        if puerto_id:
            barcos = barcos.filter(puerto_id=puerto_id)
        if fabricante_id:
            barcos = barcos.filter(fabricante_id=fabricante_id)
        if precio_min:
            try:
                barcos = barcos.filter(precio_dia__gte=float(precio_min))
            except ValueError:
                pass
        if precio_max:
            try:
                barcos = barcos.filter(precio_dia__lte=float(precio_max))
            except ValueError:
                pass
        if capacidad_min:
            try:
                barcos = barcos.filter(capacidad__gte=int(capacidad_min))
            except ValueError:
                pass

        # Marcar disponibilidad por rango de fechas
        barcos_con_disponibilidad = []
        if fecha_inicio and fecha_fin:
            try:
                inicio = datetime.strptime(fecha_inicio, '%Y-%m-%d').date()
                fin = datetime.strptime(fecha_fin, '%Y-%m-%d').date()
                for barco in barcos:
                    barco.disponible_en_rango = True
                    barcos_con_disponibilidad.append(barco)
            except ValueError:
                barcos_con_disponibilidad = list(barcos)
        else:
            barcos_con_disponibilidad = list(barcos)

        context = {
            'barcos': barcos_con_disponibilidad,
            'categorias': categorias,
            'puertos': puertos,
            'fabricantes': fabricantes,
            'categoria_id': categoria_id,
            'puerto_id': puerto_id,
            'fabricante_id': fabricante_id,
            'precio_min': precio_min,
            'precio_max': precio_max,
            'capacidad_min': capacidad_min,
            'fecha_inicio': fecha_inicio,
            'fecha_fin': fecha_fin,
        }
        return render(request, 'catalog/list.html', context)


class BarcoDetailView(View):
    def get(self, request, id):
        barco = get_object_or_404(Barco, id=id)
        context = {'barco': barco}
        return render(request, 'catalog/detail.html', context)


class SearchView(View):
    def get(self, request):
        query = request.GET.get('q', '')
        barcos = []
        categorias = Categoria.objects.all()
        puertos = Puerto.objects.all()
        fabricantes = Fabricante.objects.all()

        if query:
            barcos = Barco.objects.filter(
                Q(nombre__icontains=query) | Q(descripcion__icontains=query)
            )

        context = {
            'barcos': barcos,
            'query': query,
            'categorias': categorias,
            'puertos': puertos,
            'fabricantes': fabricantes,
        }
        return render(request, 'catalog/search.html', context)

from django import forms
