from django.shortcuts import render, redirect
from django.views import View
from django.contrib.auth import authenticate, login, logout
from django.contrib.auth.models import User
from django.contrib.auth.decorators import login_required
from django.utils.decorators import method_decorator
from django.contrib import messages
from .forms import RegistroForm, LoginForm
from .models import ClienteProfile


class RegisterView(View):
    def get(self, request):
        form = RegistroForm()
        return render(request, 'accounts/register.html', {'form': form})

    def post(self, request):
        form = RegistroForm(request.POST)
        if form.is_valid():
            user = form.save()
            ClienteProfile.objects.create(usuario=user)
            login(request, user)
            messages.success(request, 'Registro exitoso. Bienvenido a Hundidos.')
            return redirect('catalog:home')
        return render(request, 'accounts/register.html', {'form': form})


class LoginView(View):
    def get(self, request):
        form = LoginForm()
        return render(request, 'accounts/login.html', {'form': form})

    def post(self, request):
        form = LoginForm(request.POST)
        if form.is_valid():
            email = form.cleaned_data['email']
            password = form.cleaned_data['password']
            try:
                user = User.objects.get(email=email)
                user = authenticate(request, username=user.username, password=password)
                if user is not None:
                    login(request, user)
                    messages.success(request, 'Sesión iniciada correctamente.')
                    return redirect('catalog:home')
                else:
                    messages.error(request, 'Correo o contraseña incorrectos.')
            except User.DoesNotExist:
                messages.error(request, 'Correo o contraseña incorrectos.')
        return render(request, 'accounts/login.html', {'form': form})


class LogoutView(View):
    @method_decorator(login_required)
    def post(self, request):
        logout(request)
        messages.success(request, 'Sesión cerrada correctamente.')
        return redirect('catalog:home')


class ProfileView(View):
    @method_decorator(login_required)
    def get(self, request):
        try:
            profile = request.user.cliente_profile
        except ClienteProfile.DoesNotExist:
            profile = ClienteProfile.objects.create(usuario=request.user)

        context = {'profile': profile}
        return render(request, 'accounts/profile.html', context)

from django import forms
from django.core.exceptions import ValidationError
from datetime import date, timedelta


class AgregarAcestaForm(forms.Form):
    cantidad = forms.IntegerField(
        min_value=1,
        widget=forms.NumberInput(attrs={
            'class': 'form-control',
            'placeholder': 'Cantidad'
        })
    )
    fecha_inicio = forms.DateField(
        widget=forms.DateInput(attrs={
            'class': 'form-control',
            'type': 'date'
        })
    )
    fecha_fin = forms.DateField(
        widget=forms.DateInput(attrs={
            'class': 'form-control',
            'type': 'date'
        })
    )

    def clean(self):
        cleaned_data = super().clean()
        fecha_inicio = cleaned_data.get('fecha_inicio')
        fecha_fin = cleaned_data.get('fecha_fin')

        if fecha_inicio and fecha_fin:
            if fecha_inicio < date.today():
                raise ValidationError('La fecha de inicio no puede ser anterior a hoy.')
            if fecha_fin <= fecha_inicio:
                raise ValidationError('La fecha de fin debe ser posterior a la fecha de inicio.')

        return cleaned_data


